import { AIGatewayConfig, CloudflareAPIResponse } from './types';

export class AIGatewayManager {
  private baseUrl: string;
  private apiToken: string;
  private accountId: string;

  constructor(accountId: string, apiToken: string) {
    this.accountId = accountId;
    this.apiToken = apiToken;
    this.baseUrl = `https://api.cloudflare.com/client/v4/accounts/${this.accountId}/ai-gateway/gateways`;
  }

  private async request<T>(path: string, method: string, body?: any): Promise<T> {
    const url = path.startsWith('http') ? path : `${this.baseUrl}${path}`;
    const response = await fetch(url, {
      method,
      headers: {
        'Authorization': `Bearer ${this.apiToken}`,
        'Content-Type': 'application/json',
      },
      body: body ? JSON.stringify(body) : undefined,
    });

    const data = await response.json() as CloudflareAPIResponse<T>;

    if (!response.ok || !data.success) {
      const errorMsg = data.errors?.[0]?.message || 'Unknown API Error';
      const errorCode = data.errors?.[0]?.code || response.status;
      throw new Error(`Cloudflare API Error [${errorCode}]: ${errorMsg}`);
    }

    return data.result;
  }

  async createGateway(config: AIGatewayConfig): Promise<AIGatewayConfig> {
    // POST /ai-gateway/gateways
    return this.request<AIGatewayConfig>('', 'POST', config);
  }

  async getGateway(gatewayId: string): Promise<AIGatewayConfig> {
    // GET /ai-gateway/gateways/{id}
    return this.request<AIGatewayConfig>(`/${gatewayId}`, 'GET');
  }

  async listGateways(): Promise<AIGatewayConfig[]> {
    // GET /ai-gateway/gateways
    return this.request<AIGatewayConfig[]>('', 'GET');
