```typescript
import { createGateway, streamText, type LanguageModelV1 } from 'ai';
import { z } from 'zod';

/**
 * BT-001: Explicitly configures the gateway, overriding environment variables.
 */
export const createExplicitGateway = (apiKey: string) => {
  return createGateway({
    apiKey,
    // Note: baseURL defaults to https://ai-gateway.vercel.sh/v3/ai
  });
};

/**
 * BT-002: A fetch shim that captures request metadata for introspection.
 */
export const makeCapturingFetch = (callback: (url: string, headers: Headers) => void) => {
  return async (input: RequestInfo | URL, init?: RequestInit) => {
    const url = typeof input === 'string' ? input : input.toString();
    const headers = new Headers(init?.headers);
    callback(url, headers);
    return fetch(input, init);
  };
};

/**
 * BT-003: Demonstrates mid-stream cancellation using AbortController.
 */
export const streamWithAbort = async (model: LanguageModelV1, signal: AbortSignal) => {
  const result = await streamText({
    model,
    prompt: 'Write a very long essay about the history of the universe.',
    abortSignal: signal,
  });

  let content = '';
  for await (const textPart of result.textStream) {
    content += textPart;
  }
  return content;
};

/**
 * BT-004: Demonstrates v6 Tool Calling using inputSchema.
 */
export const streamWithTool = async (model: LanguageModelV1) => {
  const result = await streamText({
    model,
    prompt: 'What is the weather in San Francisco?',
    tools: {
      getWeather: {
        description: 'Get the weather in a location',
        inputSchema: z.object({
          location: z.string().describe('The city and state, e.g. San Francisco, CA'),
        }),
        execute: async ({ location }) => {
          return { location, temperature: 72, unit: 'F' };
        },
      },
    },
    // Required to allow the model to continue after tool execution
    maxSteps: 2,
  });

  return result;
};

/**
 * BT-005: Demonstrates the onFinish callback and usage tracking.
 */
export const streamWithOnFinish = async (model: LanguageModelV1) => {
  let finishData: any = null;
  const result = await streamText({
    model,
    prompt: 'Say hello!',
    onFinish: (event) => {
      finishData = event;
    },
  });

  await result.text; // Consume stream
  return { text: result.text, finishData };
};

/**
 * BT-006: Demonstrates failure mode for invalid base URLs.
 */
export const streamWithInvalidBaseURL = async (apiKey: string) => {
  const gateway = createGateway({
    apiKey,
    baseURL: 'https://this-is-a-fake-url-that-does-not-exist.dev',
  });

  const model = gateway.languageModel('openai/gpt-4o');
  const result = await streamText({
    model,
    prompt: 'Hello',
  });

  // In v6, result.text will reject if the underlying stream fails
  return await result.text;
};
